// submit.js
import { useState } from 'react';
import { useStore } from './store';
import { shallow } from 'zustand/shallow';

const selector = (s) => ({ nodes: s.nodes, edges: s.edges });

export const SubmitButton = () => {
  const { nodes, edges } = useStore(selector, shallow);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  const handleSubmit = async () => {
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const res = await fetch('http://127.0.0.1:8000/pipelines/parse', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nodes, edges }),
      });
      if (!res.ok) throw new Error(`Server error: ${res.status}`);
      const data = await res.json();
      setResult(data);
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      {/* Footer bar */}
      <div
        style={{
          position: 'fixed',
          bottom: 0,
          left: 0,
          right: 0,
          height: '56px',
          background: 'linear-gradient(180deg, #0f1420 0%, #0a0e17 100%)',
          borderTop: '1px solid rgba(255,255,255,0.06)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          gap: '16px',
          zIndex: 10,
          fontFamily: "'Inter','Segoe UI',sans-serif",
        }}
      >
        <span style={{ fontSize: 11, color: 'rgba(255,255,255,0.3)', letterSpacing: '0.05em' }}>
          {nodes.length} node{nodes.length !== 1 ? 's' : ''} · {edges.length} edge{edges.length !== 1 ? 's' : ''}
        </span>
        <button
          onClick={handleSubmit}
          disabled={loading}
          style={{
            padding: '9px 28px',
            borderRadius: '7px',
            border: 'none',
            background: loading
              ? 'rgba(99,102,241,0.4)'
              : 'linear-gradient(135deg, #6366f1, #8b5cf6)',
            color: '#fff',
            fontSize: '13px',
            fontWeight: 700,
            letterSpacing: '0.06em',
            textTransform: 'uppercase',
            cursor: loading ? 'not-allowed' : 'pointer',
            boxShadow: loading ? 'none' : '0 2px 12px rgba(99,102,241,0.4)',
            transition: 'all 0.15s',
            fontFamily: 'inherit',
          }}
          onMouseEnter={(e) => {
            if (!loading) e.currentTarget.style.transform = 'translateY(-1px)';
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = 'translateY(0)';
          }}
        >
          {loading ? 'Analyzing…' : 'Run Pipeline'}
        </button>
      </div>

      {/* Result Modal */}
      {result && (
        <div
          style={{
            position: 'fixed',
            inset: 0,
            background: 'rgba(0,0,0,0.7)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 100,
            backdropFilter: 'blur(4px)',
          }}
          onClick={() => setResult(null)}
        >
          <div
            style={{
              background: 'linear-gradient(145deg, #1a1f2e, #111827)',
              border: '1px solid rgba(255,255,255,0.1)',
              borderRadius: '14px',
              padding: '32px 36px',
              minWidth: '320px',
              boxShadow: '0 24px 60px rgba(0,0,0,0.6)',
              fontFamily: "'Inter','Segoe UI',sans-serif",
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <h2
              style={{
                margin: '0 0 4px',
                fontSize: '16px',
                fontWeight: 800,
                letterSpacing: '0.08em',
                textTransform: 'uppercase',
                background: 'linear-gradient(90deg, #a78bfa, #38bdf8)',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
              }}
            >
              Pipeline Analysis
            </h2>
            <p style={{ margin: '0 0 24px', fontSize: 12, color: 'rgba(255,255,255,0.35)' }}>
              Results from /pipelines/parse
            </p>

            <div style={{ display: 'flex', gap: '16px', marginBottom: '20px' }}>
              <StatCard label="Nodes" value={result.num_nodes} color="#22d3ee" />
              <StatCard label="Edges" value={result.num_edges} color="#a78bfa" />
            </div>

            <div
              style={{
                padding: '14px 18px',
                borderRadius: '10px',
                background: result.is_dag
                  ? 'rgba(52,211,153,0.1)'
                  : 'rgba(251,113,133,0.1)',
                border: `1px solid ${result.is_dag ? 'rgba(52,211,153,0.3)' : 'rgba(251,113,133,0.3)'}`,
                display: 'flex',
                alignItems: 'center',
                gap: '10px',
              }}
            >
              <span style={{ fontSize: '22px' }}>{result.is_dag ? '✅' : '🔄'}</span>
              <div>
                <div
                  style={{
                    fontSize: '13px',
                    fontWeight: 700,
                    color: result.is_dag ? '#34d399' : '#fb7185',
                  }}
                >
                  {result.is_dag ? 'Valid DAG' : 'Contains Cycle'}
                </div>
                <div style={{ fontSize: '11px', color: 'rgba(255,255,255,0.4)', marginTop: 2 }}>
                  {result.is_dag
                    ? 'Pipeline can be executed without circular dependencies.'
                    : 'Pipeline has circular dependencies — check your connections.'}
                </div>
              </div>
            </div>

            <button
              onClick={() => setResult(null)}
              style={{
                marginTop: '20px',
                width: '100%',
                padding: '9px',
                background: 'rgba(255,255,255,0.06)',
                border: '1px solid rgba(255,255,255,0.1)',
                borderRadius: '7px',
                color: 'rgba(255,255,255,0.7)',
                fontSize: '12px',
                fontWeight: 600,
                cursor: 'pointer',
                fontFamily: 'inherit',
                letterSpacing: '0.04em',
              }}
            >
              Close
            </button>
          </div>
        </div>
      )}

      {/* Error Modal */}
      {error && (
        <div
          style={{
            position: 'fixed',
            inset: 0,
            background: 'rgba(0,0,0,0.7)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 100,
            backdropFilter: 'blur(4px)',
          }}
          onClick={() => setError(null)}
        >
          <div
            style={{
              background: '#1a1f2e',
              border: '1px solid rgba(251,113,133,0.3)',
              borderRadius: '14px',
              padding: '28px 32px',
              minWidth: '280px',
              fontFamily: 'inherit',
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <div style={{ fontSize: '28px', marginBottom: 12 }}>⚠️</div>
            <div style={{ fontSize: '14px', fontWeight: 700, color: '#fb7185', marginBottom: 8 }}>
              Connection Error
            </div>
            <div style={{ fontSize: '12px', color: 'rgba(255,255,255,0.5)', marginBottom: 20 }}>
              {error}
            </div>
            <div style={{ fontSize: '11px', color: 'rgba(255,255,255,0.25)' }}>
              Make sure the backend is running at localhost:8000
            </div>
            <button
              onClick={() => setError(null)}
              style={{
                marginTop: '16px',
                width: '100%',
                padding: '8px',
                background: 'rgba(251,113,133,0.1)',
                border: '1px solid rgba(251,113,133,0.3)',
                borderRadius: '6px',
                color: '#fb7185',
                fontSize: '12px',
                cursor: 'pointer',
                fontFamily: 'inherit',
              }}
            >
              Dismiss
            </button>
          </div>
        </div>
      )}
    </>
  );
};

const StatCard = ({ label, value, color }) => (
  <div
    style={{
      flex: 1,
      padding: '14px',
      background: 'rgba(255,255,255,0.04)',
      border: '1px solid rgba(255,255,255,0.08)',
      borderRadius: '10px',
      textAlign: 'center',
    }}
  >
    <div style={{ fontSize: '28px', fontWeight: 800, color, lineHeight: 1 }}>{value}</div>
    <div style={{ fontSize: '10px', color: 'rgba(255,255,255,0.4)', marginTop: 4, letterSpacing: '0.1em', textTransform: 'uppercase' }}>{label}</div>
  </div>
);
